#!/usr/bin/env bash
# third_party/common.sh - 第三方库公共函数库
# 提供第三方库管理所需的公共函数

# ================================================================
# 加载依赖
# ================================================================
THIRD_PARTY_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "${THIRD_PARTY_DIR}/../.." && pwd)"

# 加载主公共库
source "${PROJECT_ROOT}/scripts/lib/common.sh"

# 加载配置（延迟加载，确保 qt.conf 已经被 source）
third_party_load_config() {
    local config_file="${PROJECT_ROOT}/config/third_party.conf"
    if [[ -f "$config_file" ]]; then
        source "$config_file"
    else
        die "Configuration file not found: $config_file"
    fi
}

# ================================================================
# 日志函数（使用主公共库的日志函数）
# ================================================================

# ================================================================
# 库信息获取函数
# ================================================================

# 获取库是否启用
third_party_get_enabled() {
    local lib="$1"
    local enabled_var="${lib^^}_ENABLED"
    echo "${!enabled_var:-true}"
}

# 获取库的 sysroot 路径
third_party_get_sysroot() {
    local lib="$1"
    echo "${THIRD_PARTY_SYSROOT}"
}

# 获取库的安装路径（在 sysroot 内）
third_party_get_install_path() {
    local lib="$1"
    echo "${THIRD_PARTY_SYSROOT}"
}

# 获取库的库文件路径
third_party_get_lib_path() {
    local lib="$1"
    local sysroot="$(third_party_get_sysroot "${lib}")"
    local arch="${2:-armhf}"

    # 尝试常见的库路径
    for lib_dir in \
        "${sysroot}/usr/lib/${arch}-linux-gnu" \
        "${sysroot}/usr/lib/${arch}-linux-gnueabihf" \
        "${sysroot}/usr/lib/arm-linux-gnueabihf" \
        "${sysroot}/usr/lib/aarch64-linux-gnu" \
        "${sysroot}/usr/lib" \
        "${sysroot}/lib/${arch}-linux-gnu" \
        "${sysroot}/lib/${arch}-linux-gnueabihf" \
        "${sysroot}/lib/arm-linux-gnueabihf" \
        "${sysroot}/lib/aarch64-linux-gnu" \
        "${sysroot}/lib"
    do
        if [[ -d "$lib_dir" ]]; then
            echo "$lib_dir"
            return 0
        fi
    done

    return 1
}

# ================================================================
# 下载函数
# ================================================================

# 下载文件（带进度显示）
third_party_download() {
    local url="$1"
    local dest="$2"
    local filename="${dest:-$(basename "$url")}"

    # 如果目标已存在且非空，直接返回
    if [[ -f "$filename" && -s "$filename" ]]; then
        echo "$filename"
        return 0
    fi

    # 确保目标目录存在
    local dest_dir="$(dirname "$filename")"
    mkdir -p "$dest_dir"

    # Download file
    if wget -q -O "$filename" "$url"; then
        echo "$filename"
        return 0
    else
        log_warn "Failed to download: $url"
        rm -f "$filename"
        return 1
    fi
}

# ================================================================
# 解压函数
# ================================================================

# 自动识别格式并解压
third_party_extract() {
    local archive="$1"
    local dest_dir="${2:-.}"

    mkdir -p "$dest_dir"

    log_info "Extracting: $(basename "$archive")"

    case "$archive" in
        *.tar.xz|*.txz)
            tar -xf "$archive" -C "$dest_dir"
            ;;
        *.tar.gz|*.tgz)
            tar -xzf "$archive" -C "$dest_dir"
            ;;
        *.tar.bz2|*.tbz2)
            tar -xjf "$archive" -C "$dest_dir"
            ;;
        *.zip)
            unzip -q "$archive" -d "$dest_dir"
            ;;
        *.deb)
            dpkg-deb -x "$archive" "$dest_dir"
            ;;
        *)
            die "Unsupported archive format: $archive"
            ;;
    esac

    log_ok "Extracted to: $dest_dir"
}

# ================================================================
# CMake 配置生成函数
# ================================================================

# 生成库的 CMake 配置片段
third_party_generate_cmake_fragment() {
    local lib="$1"
    local lib_path="$2"
    local include_dir="$3"
    local config_file="${THIRD_PARTY_SYSROOT}/lib/cmake/${lib^^}/${lib^^}Config.cmake"

    mkdir -p "$(dirname "$config_file")"

    cat > "$config_file" <<EOF
# Auto-generated by third_party manager
# Library: ${lib}

add_library(${lib}::${lib} SHARED IMPORTED)

set_target_properties(${lib}::${lib} PROPERTIES
    IMPORTED_LOCATION "${lib_path}"
    INTERFACE_INCLUDE_DIRECTORIES "${include_dir}"
)
EOF

    echo "$config_file"
}

# 生成统一的 CMake 配置片段（用于工具链文件）
third_party_generate_cmake_fragment_for_toolchain() {
    local fragment_file="${THIRD_PARTY_SYSROOT}/third-party-cmake-fragment.cmake"

    cat > "$fragment_file" <<EOF
# ================================================================
# Third-Party Libraries CMake Configuration
# Auto-generated by third_party manager
# ================================================================

# Third-party sysroot
set(THIRD_PARTY_SYSROOT "${THIRD_PARTY_SYSROOT}")

# Add to CMAKE_FIND_ROOT_PATH
list(APPEND CMAKE_FIND_ROOT_PATH "${THIRD_PARTY_SYSROOT}")

# Add to CMAKE_PREFIX_PATH
list(APPEND CMAKE_PREFIX_PATH "${THIRD_PARTY_SYSROOT}/lib/cmake")
list(APPEND CMAKE_PREFIX_PATH "${THIRD_PARTY_SYSROOT}")

# Add to search paths
set(CMAKE_INCLUDE_PATH "${THIRD_PARTY_SYSROOT}/usr/include" \${CMAKE_INCLUDE_PATH})
set(CMAKE_LIBRARY_PATH "${THIRD_PARTY_SYSROOT}/usr/lib" \${CMAKE_LIBRARY_PATH})
EOF

    # 为每个已安装的库添加特定配置
    for lib in ${THIRD_PARTY_LIBS}; do
        if [[ "$(third_party_get_enabled "$lib")" == "true" ]]; then
            local lib_path
            lib_path=$(third_party_get_lib_path "$lib")

            if [[ -n "$lib_path" && -d "$lib_path" ]]; then
                echo "" >> "$fragment_file"
                echo "# ${lib^^}" >> "$fragment_file"
                echo "set(CMAKE_LIBRARY_PATH \"${lib_path}\" \${CMAKE_LIBRARY_PATH})" >> "$fragment_file"
            fi
        fi
    done

    echo "$fragment_file"
}

# ================================================================
# 状态检查函数
# ================================================================

# 检查库是否已安装
third_party_is_installed() {
    local lib="$1"
    local sysroot="$(third_party_get_sysroot "$lib")"

    # 检查是否有标记文件
    if [[ -f "${sysroot}/.${lib}-installed" ]]; then
        return 0
    fi

    return 1
}

# 标记库为已安装
third_party_mark_installed() {
    local lib="$1"
    local sysroot="$(third_party_get_sysroot "$lib")"
    touch "${sysroot}/.${lib}-installed"
}

# 取消库已安装标记
third_party_unmark_installed() {
    local lib="$1"
    local sysroot="$(third_party_get_sysroot "$lib")"
    rm -f "${sysroot}/.${lib}-installed"
}

# ================================================================
# 初始化函数
# ================================================================

# 初始化 third_party 环境
third_party_init() {
    # 创建必要的目录
    mkdir -p "${THIRD_PARTY_SYSROOT}"
    mkdir -p "${THIRD_PARTY_DL_DIR}"
    mkdir -p "${THIRD_PARTY_SYSROOT}/usr/include"
    mkdir -p "${THIRD_PARTY_SYSROOT}/usr/lib"
    mkdir -p "${THIRD_PARTY_SYSROOT}/lib/cmake"
    mkdir -p "${THIRD_PARTY_SYSROOT}/lib/pkgconfig"
}

# 导出所有库的信息（供 manager.sh 使用）
third_party_export_libs_info() {
    for lib in ${THIRD_PARTY_LIBS}; do
        THIRD_PARTY_LIB_REGISTRY["${lib}_ENABLED"]="$(third_party_get_enabled "$lib")"
        THIRD_PARTY_LIB_REGISTRY["${lib}_PATH"]="$(third_party_get_install_path "$lib")"
    done
}
